-- ADVOCIS — Civil Rights Case Law
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_024', 'ADVOCIS', 'CASE_LAW', 'US', 'Monell v. Department of Social Services (1978) 436 U.S. 658', 'Monell', 'Municipal Liability Under § 1983', 'Municipalities can be held liable under § 1983 when a policy or custom causes a constitutional deprivation.', '["Municipality liable for official policy or custom","No respondeat superior for isolated acts","Failure to train can be policy if deliberate indifference","Custom need not be formally adopted"]', '[{"section":"Holding","description":"Municipal liability for policy/custom — not respondeat superior"},{"section":"Custom","description":"Persistent and widespread practice constitutes custom"}]', '["1983_complaint","Monell_claim","municipal_liability","policy_challenge"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_025', 'ADVOCIS', 'CASE_LAW', 'US', 'Graham v. Connor (1989) 490 U.S. 386', 'Graham v. Connor', 'Objective Reasonableness Standard for Use of Force', 'All claims of excessive force by law enforcement analyzed under Fourth Amendment objective reasonableness standard.', '["Objective reasonableness standard","Judged from perspective of reasonable officer on scene","Considers severity of crime, immediate threat, active resistance","Not judged with 20/20 hindsight"]', '[{"section":"Holding","description":"4th Amendment governs excessive force claims"},{"section":"Test","description":"Objective reasonableness — totality of circumstances"}]', '["use_of_force_report","excessive_force_complaint","1983_complaint","police_report"]', '["constitutional-and-civil-rights-audit","police-report-data-cross-reference"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_026', 'ADVOCIS', 'CASE_LAW', 'US', 'Troxel v. Granville (2000) 530 U.S. 57', 'Troxel', 'Fundamental Right of Parents to Direct Upbringing', 'Parents have a fundamental liberty interest in the care, custody, and control of their children protected by substantive due process.', '["Fundamental right under 14th Amendment","Fit parents presumption — court must give special weight to parent wishes","State cannot infringe without compelling interest","Applies to custody, visitation, and education decisions"]', '[{"section":"Holding","description":"Parental rights are fundamental liberty interest"},{"section":"Standard","description":"Special weight to parents wishes — fit parent presumption"}]', '["custody_order","visitation_order","grandparent_visitation","parental_rights"]', '["constitutional-and-civil-rights-audit","california-family-law-expansion-audit"]', 'Federal / State Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_027', 'ADVOCIS', 'CASE_LAW', 'US', 'Santosky v. Kramer (1982) 455 U.S. 745', 'Santosky', 'Clear and Convincing Evidence for Parental Rights Termination', 'Before a state may sever the parent-child relationship, due process requires clear and convincing evidence.', '["Clear and convincing evidence standard required","Preponderance of evidence is insufficient for termination","Fundamental liberty interest of parents at stake","Applies to all states through 14th Amendment"]', '[{"section":"Holding","description":"Clear and convincing evidence required for TPR"},{"section":"Due Process","description":"14th Amendment protects parental rights"}]', '["TPR_petition","dependency_proceeding","parental_rights_order"]', '["constitutional-and-civil-rights-audit","california-cps-child-welfare-audit"]', 'Federal / State Courts', 1, 1, datetime('now'), datetime('now'));

