VALUES
('std_reg_069', 'REGULIS', 'CASE_LAW', 'CA', 'Green v. Superior Court (1974) 10 Cal.3d 616', 'Green v. Superior Court', 'Implied Warranty of Habitability', 'Landmark California case establishing implied warranty of habitability in residential leases — tenant may withhold rent for uninhabitable conditions.', '["Implied warranty of habitability in every residential lease","Material breach excuses rent payment","Conditions must be substantial, not trivial","Remedies include rent withholding and repair-and-deduct"]', '[{"section":"Holding","description":"Implied warranty of habitability exists in California residential leases"},{"section":"Remedy","description":"Tenant may withhold rent for material breach"}]', '["habitability_complaint","rent_withholding","repair_request","unlawful_detainer_defense"]', '["california-housing-tenant-rights-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

