VALUES
('std_reg_070', 'REGULIS', 'CASE_LAW', 'CA', 'Marriage of Feldman (2007) 153 Cal.App.4th 1470', 'Feldman', 'Fiduciary Duty Breach — Community Property Concealment', 'Remedies for breach of fiduciary duty between spouses including 100% award of concealed assets.', '["Non-disclosing spouse may forfeit concealed asset entirely","Remedies include 50/100% of undisclosed asset plus attorney fees","Court may impose sanctions","Applies post-separation through final division"]', '[{"section":"Holding","description":"100% of undisclosed asset awarded to innocent spouse"},{"section":"Remedy","description":"FC §1101(h) sanctions for breach of fiduciary duty"}]', '["disclosure_violation","hidden_asset","FL-140","property_division"]', '["california-family-law-expansion-audit","california-real-estate-transaction-fraud-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

