VALUES
('std_reg_071', 'REGULIS', 'CASE_LAW', 'CA', 'Moradi-Shalal v. Fireman''s Fund (1988) 46 Cal.3d 287', 'Moradi-Shalal', 'No Private Right of Action Under Insurance Code § 790.03', 'There is no private cause of action for violation of the unfair claims practices provisions of the Insurance Code.', '["No direct suit under IC § 790.03","Must bring bad faith tort claim instead","Egan v. Mutual of Omaha remains for bad faith tort","DOI administrative enforcement still available"]', '[{"section":"Holding","description":"No private right of action under IC § 790.03"},{"section":"Alternative","description":"Bad faith tort action under covenant of good faith"}]', '["insurance_complaint","bad_faith_claim","denial_letter"]', '["california-insurance-bad-faith-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

