('std_eth_014', 'ETHICARA', 'CASE_LAW', 'CA', 'People v. Kelly (1976) 17 Cal.3d 24', 'Kelly / Kelly-Frye', 'Scientific Evidence Admissibility — California Standard', 'California standard for admissibility of new scientific evidence — must be generally accepted in the relevant scientific community (Kelly-Frye test).', '["New scientific technique must be generally accepted in relevant field","Testimony from qualified expert required","Court acts as gatekeeper","Applies in California state courts (not Daubert)"]', '[{"section":"Holding","description":"General acceptance test for new scientific evidence in California"},{"section":"Three-prong test","description":"Reliability of method, qualification of witness, correct procedures"}]', '["expert_testimony","scientific_evidence","forensic_report","motion_to_exclude"]', '["abpn-psychiatry-and-neurology-standards-audit","forensic-photo-comparison-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

