INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_025', 'FISCARA', 'CASE_LAW', 'US', 'Safeco Ins. Co. v. Burr (2007) 551 U.S. 47', 'Safeco v. Burr', 'Willful FCRA Violation Standard', 'Willful violation of FCRA requires knowing or reckless disregard — good faith reading of statute defeats willfulness.', '["Willful requires knowing or reckless disregard of FCRA requirements","Reasonable but erroneous interpretation is not willful","Statutory damages ($100-$1,000) only for willful violations","Negligent violations: actual damages only"]', '[{"section":"Holding","description":"Reckless disregard of statutory duty satisfies willfulness"},{"section":"Safe harbor","description":"Good faith interpretation of FCRA defeats willfulness claim"}]', '["FCRA_complaint","adverse_action_notice","consumer_dispute","willful_violation"]', '["fcra-chexsystems-consumer-report-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));


