('std_adv_028', 'ADVOCIS', 'CONSTITUTIONAL', 'US', 'U.S. Const. amend. V', '5th Amendment', 'Fifth Amendment — Due Process, Self-Incrimination, Double Jeopardy', 'Federal due process, protection against self-incrimination, double jeopardy, and takings without just compensation.', '["Grand jury indictment for capital crimes","No double jeopardy","No compelled self-incrimination (Miranda)","Due process of law before deprivation","Just compensation for takings"]', '[{"section":"Due Process Clause","description":"Federal government cannot deprive life, liberty, property without due process"},{"section":"Self-Incrimination Clause","description":"Cannot be compelled to be a witness against oneself"},{"section":"Takings Clause","description":"Private property cannot be taken without just compensation"}]', '["criminal_defense","Miranda_warning","grand_jury","eminent_domain","federal_complaint"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

